class PlaylistManager{constructor(){this.knownSongs=new Set();this.currentFilter='all';this.hideKnownSongs=false;this.searchTerm='';this.selectedArtist='';this.isOffline=!navigator.onLine;this.init();}init(){this.loadUserPreferences();this.setupEventListeners();this.populateArtistFilter();this.setupOfflineHandling();}async loadUserPreferences(){try{const response=await fetch('/api/v1/user/preferences');if(response.ok){const data=await response.json();this.knownSongs=new Set(data.known_songs||[]);}else{this.loadPreferencesFromStorage();}}catch(error){console.log('Loading preferences from localStorage (offline)');this.loadPreferencesFromStorage();}this.updateSongCheckboxes();}loadPreferencesFromStorage(){const stored=localStorage.getItem('knownSongs');if(stored){this.knownSongs=new Set(JSON.parse(stored));}}savePreferencesToStorage(){localStorage.setItem('knownSongs',JSON.stringify([...this.knownSongs]));}updateSongCheckboxes(){this.knownSongs.forEach(songId=>{const checkbox=document.getElementById(`song-${songId}`);if(checkbox){checkbox.checked=true;checkbox.closest('.song-item').dataset.known='true';checkbox.closest('.song-item').classList.add('known-song');}});}setupEventListeners(){document.querySelectorAll('.filter-tab').forEach(tab=>{tab.addEventListener('click',(e)=>this.handleFilterTab(e));});const searchInput=document.getElementById('song-search');if(searchInput){let searchTimeout;searchInput.addEventListener('input',(e)=>{clearTimeout(searchTimeout);searchTimeout=setTimeout(()=>{this.searchTerm=e.target.value.toLowerCase();this.filterSongs();},300);});}const artistFilter=document.getElementById('artist-filter');if(artistFilter){artistFilter.addEventListener('change',(e)=>{this.selectedArtist=e.target.value;this.filterSongs();});}const toggleBtn=document.getElementById('toggle-known-btn');if(toggleBtn){toggleBtn.addEventListener('click',()=>this.toggleKnownSongs());}document.addEventListener('change',(e)=>{if(e.target.classList.contains('song-known-checkbox')){const songId=e.target.id.replace('song-','');this.toggleSongKnown(songId,e.target.checked);}});document.addEventListener('keydown',(e)=>this.handleKeyboardShortcuts(e));window.addEventListener('online',()=>this.handleOnline());window.addEventListener('offline',()=>this.handleOffline());}handleFilterTab(e){document.querySelectorAll('.filter-tab').forEach(t=>t.classList.remove('active'));e.target.classList.add('active');this.currentFilter=e.target.dataset.filter;this.filterSongs();}toggleKnownSongs(){this.hideKnownSongs=!this.hideKnownSongs;const toggleBtn=document.getElementById('toggle-known-btn');toggleBtn.textContent=this.hideKnownSongs?'👁️ Show Known Songs':'👁️ Hide Known Songs';toggleBtn.classList.toggle('active',this.hideKnownSongs);this.filterSongs();}async toggleSongKnown(songId,isKnown){const songItem=document.querySelector(`[data-song-id="${songId}"]`);if(isKnown){this.knownSongs.add(songId);songItem.classList.add('known-song');}else{this.knownSongs.delete(songId);songItem.classList.remove('known-song');}songItem.dataset.known=isKnown.toString();this.savePreferencesToStorage();try{const response=await fetch('/api/v1/user/preferences/song',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({song_id:songId,is_known:isKnown})});if(!response.ok){throw new Error('Failed to sync preference');}this.showSyncStatus(songItem,'synced');}catch(error){console.log('Preference saved offline, will sync when online');this.storeOfflinePreference(songId,isKnown);this.showSyncStatus(songItem,'offline');}this.filterSongs();}storeOfflinePreference(songId,isKnown){const offlinePrefs=JSON.parse(localStorage.getItem('offlinePreferences')||'[]');const filtered=offlinePrefs.filter(pref=>pref.song_id!==songId);filtered.push({song_id:songId,is_known:isKnown,timestamp:Date.now()});localStorage.setItem('offlinePreferences',JSON.stringify(filtered));}showSyncStatus(songItem,status){const existingIndicator=songItem.querySelector('.sync-indicator');if(existingIndicator){existingIndicator.remove();}const indicator=document.createElement('span');indicator.className=`sync-indicator sync-${status}`;indicator.textContent=status==='synced'?'✓':'📱';indicator.title=status==='synced'?'Synced':'Saved offline';songItem.querySelector('.song-meta').appendChild(indicator);setTimeout(()=>{indicator.remove();},2000);}filterSongs(){const songItems=document.querySelectorAll('.song-item');let visibleCount=0;songItems.forEach(item=>{const songTitle=item.querySelector('.song-title').textContent.toLowerCase();const songArtist=item.querySelector('.song-artist').textContent;const isKnown=item.dataset.known==='true';let shouldShow=true;if(this.searchTerm&&!songTitle.includes(this.searchTerm)&&!songArtist.toLowerCase().includes(this.searchTerm)){shouldShow=false;}if(this.selectedArtist&&songArtist!==this.selectedArtist){shouldShow=false;}if(this.currentFilter==='known'&&!isKnown){shouldShow=false;}else if(this.currentFilter==='unknown'&&isKnown){shouldShow=false;}if(this.hideKnownSongs&&isKnown){shouldShow=false;}if(shouldShow){item.style.display='flex';item.classList.add('visible');visibleCount++;}else{item.style.display='none';item.classList.remove('visible');}});this.updateEmptyState(visibleCount);this.updateFilterCounts();}updateEmptyState(visibleCount){const emptyState=document.getElementById('empty-state');if(emptyState){emptyState.style.display=visibleCount===0?'block':'none';}}updateFilterCounts(){const allCount=document.querySelectorAll('.song-item').length;const knownCount=document.querySelectorAll('.song-item[data-known="true"]').length;const unknownCount=allCount-knownCount;const allTab=document.querySelector('[data-filter="all"]');const knownTab=document.querySelector('[data-filter="known"]');const unknownTab=document.querySelector('[data-filter="unknown"]');if(allTab)allTab.textContent=`All Songs(${allCount})`;if(knownTab)knownTab.textContent=`Known(${knownCount})`;if(unknownTab)unknownTab.textContent=`Unknown(${unknownCount})`;}populateArtistFilter(){const artists=new Set();document.querySelectorAll('.song-artist').forEach(element=>{artists.add(element.textContent);});const artistFilter=document.getElementById('artist-filter');if(artistFilter){Array.from(artists).sort().forEach(artist=>{const option=document.createElement('option');option.value=artist;option.textContent=artist;artistFilter.appendChild(option);});}}handleKeyboardShortcuts(e){if((e.ctrlKey||e.metaKey)&&e.key==='f'){e.preventDefault();const searchInput=document.getElementById('song-search');if(searchInput){searchInput.focus();}}if(e.key==='h'&&!e.ctrlKey&&!e.metaKey&&!e.altKey){const activeElement=document.activeElement;if(activeElement.tagName!=='INPUT'&&activeElement.tagName!=='TEXTAREA'){this.toggleKnownSongs();}}if(['1','2','3'].includes(e.key)&&!e.ctrlKey&&!e.metaKey&&!e.altKey){const activeElement=document.activeElement;if(activeElement.tagName!=='INPUT'&&activeElement.tagName!=='TEXTAREA'){const tabs=document.querySelectorAll('.filter-tab');const index=parseInt(e.key)-1;if(tabs[index]){tabs[index].click();}}}}setupOfflineHandling(){this.updateOfflineIndicator();}async handleOnline(){this.isOffline=false;this.updateOfflineIndicator();await this.syncOfflinePreferences();if(window.FestivalPlaylistApp){window.FestivalPlaylistApp.showNotification('Back online! Syncing your preferences...','success');}}handleOffline(){this.isOffline=true;this.updateOfflineIndicator();if(window.FestivalPlaylistApp){window.FestivalPlaylistApp.showNotification('You are offline. Changes will be saved locally.','info');}}updateOfflineIndicator(){const playlistHeader=document.querySelector('.playlist-header');if(!playlistHeader)return;let indicator=document.getElementById('offline-indicator');if(this.isOffline){if(!indicator){indicator=document.createElement('div');indicator.id='offline-indicator';indicator.className='offline-indicator';indicator.innerHTML='📱 Offline mode - changes saved locally';playlistHeader.appendChild(indicator);}}else{if(indicator){indicator.remove();}}}async syncOfflinePreferences(){const offlinePrefs=JSON.parse(localStorage.getItem('offlinePreferences')||'[]');if(offlinePrefs.length===0)return;console.log('Syncing offline preferences...');for(const pref of offlinePrefs){try{const response=await fetch('/api/v1/user/preferences/song',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({song_id:pref.song_id,is_known:pref.is_known})});if(response.ok){console.log('Synced preference for song:',pref.song_id);}}catch(error){console.error('Failed to sync preference:',error);return;}}localStorage.removeItem('offlinePreferences');console.log('All offline preferences synced successfully');}markAllAsKnown(){const songItems=document.querySelectorAll('.song-item:not([data-known="true"])');songItems.forEach(item=>{const songId=item.dataset.songId;const checkbox=item.querySelector('.song-known-checkbox');if(checkbox){checkbox.checked=true;this.toggleSongKnown(songId,true);}});}markAllAsUnknown(){const songItems=document.querySelectorAll('.song-item[data-known="true"]');songItems.forEach(item=>{const songId=item.dataset.songId;const checkbox=item.querySelector('.song-known-checkbox');if(checkbox){checkbox.checked=false;this.toggleSongKnown(songId,false);}});}exportPlaylistState(){const playlistData={knownSongs:[...this.knownSongs],filters:{currentFilter:this.currentFilter,hideKnownSongs:this.hideKnownSongs,searchTerm:this.searchTerm,selectedArtist:this.selectedArtist},timestamp:Date.now()};const blob=new Blob([JSON.stringify(playlistData,null,2)],{type:'application/json'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='playlist-preferences.json';a.click();URL.revokeObjectURL(url);}}document.addEventListener('DOMContentLoaded',function(){if(document.querySelector('.playlist-header')){window.playlistManager=new PlaylistManager();}});window.PlaylistManager=PlaylistManager;